import{_ as e,o,c as t,a3 as i}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"XiHan.Framework.Analyzers","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/analyzers.md","filePath":"cosmos/framework/packages/analyzers.md","lastUpdated":1783216089000}'),s={name:"cosmos/framework/packages/analyzers.md"};function r(l,a,n,d,c,h){return o(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="xihan-framework-analyzers" tabindex="-1">XiHan.Framework.Analyzers <a class="header-anchor" href="#xihan-framework-analyzers" aria-label="Permalink to &quot;XiHan.Framework.Analyzers&quot;">​</a></h1><blockquote><p>Roslyn 代码分析器：编译期规范检查。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Analyzers</code></li><li><strong>模块类</strong>：—（作为 Analyzer 引用，编译期生效，无运行时模块类）</li><li><strong>所在层</strong>：工具/分析器</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Analyzers 是一个基于 Roslyn 的代码分析器（<code>DiagnosticAnalyzer</code>），在<strong>编译期</strong>检查源码是否符合框架规范，并在 IDE 中提供 Code Fix 一键修复。它以 <code>netstandard2.0</code> 构建、作为 analyzer 打包（<code>analyzers/dotnet/cs</code>），是开发期依赖（<code>DevelopmentDependency</code>），不进入运行时。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>想在编译/编码阶段自动强制项目的代码规范，把问题拦在 CI 之前。</li><li>希望 IDE 直接给出诊断提示并提供自动修复。</li><li>统一团队协作下所有文件的规范一致性。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Analyzers</span></span></code></pre></div><p>也可在开发期通过项目引用接入（<code>OutputItemType=&quot;Analyzer&quot;</code>、<code>ReferenceOutputAssembly=&quot;false&quot;</code>、<code>PrivateAssets=&quot;all&quot;</code>）。</p><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><p>分析器包，引用后在编译期自动生效，无需 <code>[DependsOn]</code> 或任何运行时接入。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li>编译期扫描 C# 源码并产出诊断，IDE 中同步提示。</li><li>随附 <code>CodeFixProvider</code>，可一键自动修复不符合规范的文件。</li><li>诊断级别可在 <code>.editorconfig</code> 中按 <code>dotnet_diagnostic.&lt;ID&gt;.severity</code> 逐条调整（<code>warning</code> / <code>error</code> / <code>none</code>），支持按目录覆盖（如排除 <code>Migrations</code>）。</li></ul><h2 id="规则" tabindex="-1">规则 <a class="header-anchor" href="#规则" aria-label="Permalink to &quot;规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>规则 ID</th><th>说明</th></tr></thead><tbody><tr><td><code>XHFH001</code></td><td>文件缺少或未正确声明曦寒标准版权文件头</td></tr></tbody></table><h2 id="快速示例" tabindex="-1">快速示例 <a class="header-anchor" href="#快速示例" aria-label="Permalink to &quot;快速示例&quot;">​</a></h2><p>在 <code>.editorconfig</code> 中控制诊断级别（改为 <code>error</code> 可让编译失败）：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[*.cs]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dotnet_diagnostic.XHFH001.severity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = warning</span></span></code></pre></div><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><p>无框架内部依赖。开发期依赖 <code>Microsoft.CodeAnalysis.Analyzers</code>、<code>Microsoft.CodeAnalysis.CSharp.Workspaces</code>、<code>System.Composition.AttributedModel</code>（均 <code>PrivateAssets=&quot;all&quot;</code>，不外泄给消费方）。</p><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./utils">XiHan.Framework.Utils</a> — 在编译期引用本分析器做文件头规范检查。</li><li><a href="./core">XiHan.Framework.Core</a> — 框架核心库。</li></ul>`,23)])])}const k=e(s,[["render",r]]);export{u as __pageData,k as default};
